"""
Scorecard data migration — loads all 8 periods (Last Week, Current Month, Last Month, Year, Q1-Q4)
from the Walmart Scintilla weekly scorecard Excel report.

Run once on startup if scorecard data is missing Q1-Q4 periods.
"""
import json, base64, zlib, logging

logger = logging.getLogger("scorecard_migration")

_SCORECARD_DATA = ""


def migrate_scorecard_periods(con):
    """Load full scorecard data with all 8 periods if Q1 data is missing."""
    try:
        # Check if Q1 data already exists WITH normalized metric names
        # (old data may have unnormalized names like "POS Sales in dollars" instead of "POS Sales $")
        result = con.execute(
            "SELECT COUNT(*) FROM walmart_scorecard WHERE period = ? AND metric_name = ?",
            ["Q1", "POS Sales $"]
        ).fetchone()
        if result and result[0] > 0:
            logger.info(f"Scorecard Q1 data with normalized names already present ({result[0]} rows), skipping migration")
            return 0

        # Decode embedded data
        compressed = base64.b64decode(_SCORECARD_DATA)
        raw = zlib.decompress(compressed)
        rows = json.loads(raw)

        logger.info(f"Loading {len(rows)} scorecard rows (8 periods × 3 vendors × 27 metrics)")

        # First, clear existing scorecard data to avoid conflicts
        # (INSERT OR IGNORE would skip rows that already exist with old naming)
        con.execute("DELETE FROM walmart_scorecard WHERE 1=1")

        count = 0
        for r in rows:
            try:
                con.execute(
                    """INSERT INTO walmart_scorecard
                       (vendor_section, metric_group, metric_name, period, period_range,
                        value_ty, value_ly, value_diff, report_date, upload_id,
                        division, customer, platform)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, '2026-03-16', 'migration_v2',
                            'golf', 'walmart_stores', 'scintilla')""",
                    [
                        r["vendor_section"],
                        r["metric_group"],
                        r["metric_name"],
                        r["period"],
                        r.get("period_range"),
                        r.get("value_ty"),
                        r.get("value_ly"),
                        r.get("value_diff"),
                    ],
                )
                count += 1
            except Exception as e:
                logger.error(f"Scorecard row insert error: {e}")

        logger.info(f"Scorecard migration complete: {count}/{len(rows)} rows loaded")
        return count
    except Exception as e:
        logger.error(f"Scorecard migration failed: {e}")
        return 0
